27→    }
28→
29→    /**
30→     * Generates a single valid PyBoolObj within the random domain.
31→     *
32→     * @return a single PyBoolObj selected from the random domain
33→     */
34→    @Override
35→    public PyBoolObj genRandVal() {
36→        return new PyBoolObj(this.ranDomainChoice().intValue() > 0);
37→    }
