  3→import main.rice.obj.APyObj;
  4→import main.rice.obj.PyDictObj;
  5→import java.util.*;
  6→
  7→/**
  8→ * A representation of a node for generating PyDictObjs.
  9→ *
 10→ * @param <KeyType> the type of object generated by the leftChild node, which represents
 11→ *                  the type of the keys in the dictionary; if we invoke
 12→ *                  this.leftChild.genExVals(), it will return List<KeyType>
 13→ * @param <ValType> the type of object generated by the rightChild node, which represents
 14→ *                  the type of the values in the dictionary; if we invoke
 15→ *                  this.leftChild.genExVals(), it will return List<ValType>
 16→ */
 17→public class PyDictNode<KeyType extends APyObj, ValType extends APyObj>
 18→        extends APyNode<PyDictObj<KeyType, ValType>> {
 19→
 20→    /**
 21→     * Overrides the leftChild in the superclass (APyNode) with a more specific type: a
 22→     * generator of KeyType objects.
 23→     */
 24→    protected APyNode<KeyType> leftChild;
 25→
 26→    /**
 27→     * Overrides the leftChild in the superclass (APyNode) with a more specific type: a
 28→     * generator of ValType objects.
 29→     */
 30→    protected APyNode<ValType> rightChild;
 31→
 32→    /**
 33→     * Constructor for a PyDictNode; stores references to the keyChild (this.leftChild)
 34→     * and valChild (this.rightChild).
 35→     *
 36→     * @param keyChild a node representing the valid keys for this dictionary
 37→     * @param valChild a node representing the valid values for this dictionary
 38→     */
 39→    public PyDictNode(APyNode<KeyType> keyChild, APyNode<ValType> valChild) {
 40→        this.leftChild = keyChild;
 41→        this.rightChild = valChild;
 42→    }
 43→
 44→    /**
 45→     * Returns the left child node.
 46→     *
 47→     * @return the left child node
 48→     */
 49→    @Override
 50→    public APyNode<KeyType> getLeftChild() {
 51→        return this.leftChild;
 52→    }
 53→
 54→    /**
 55→     * Returns the right child node.
 56→     *
 57→     * @return the right child node
 58→     */
 59→    @Override
 60→    public APyNode<ValType> getRightChild() {
 61→        return this.rightChild;
 62→    }
 63→
 64→    /**
 65→     * Generates all valid PyDictObjs within the exhaustive domain; begins by generating
 66→     * all valid keys and values, and then generates all permutations of (key, value)
 67→     * pairs of valid length (as constrained by the exhaustive domain).
 68→     *
 69→     * @return a set of PyDictObjs comprising the exhaustive domain
 70→     */
 71→    @Override
 72→    public Set<PyDictObj<KeyType, ValType>> genExVals() {
 73→        // Generate all valid keys and values
 74→        Set<KeyType> keyVals = this.leftChild.genExVals();
 75→        Set<ValType> valVals = this.rightChild.genExVals();
 76→
 77→        // Generate all permutations of valid (key, value) pairs of valid length
 78→        return this.genDictPerms(keyVals, valVals);
 79→    }
 80→
 81→    /**
 82→     * Generates a single valid PyDictObj within the random domain; begins by randomly
 83→     * selecting the size, n (number of (key, value) pairs), and then randomly selects
 84→     * valid (key, value) pairs until there are n unique (key, value) pairs.
 85→     *
 86→     * @return a single PyDictObj selected from the random domain
 87→     */
 88→    @Override
 89→    public PyDictObj<KeyType, ValType> genRandVal() {
 90→        // Randomly select the size, n
 91→        int size = this.ranDomainChoice().intValue();
 92→
 93→        // Randomly select n (key, value) pairs; make sure to continuously monitor the
 94→        // size, as we could generate the same key twice resulting in the size not
 95→        // increasing from one iteration to the next
 96→        Map<KeyType, ValType> map = new HashMap<>();
 97→        while (map.size() < size) {
 98→            KeyType key = this.leftChild.genRandVal();
 99→            ValType val = this.rightChild.genRandVal();
100→            map.put(key, val);
101→        }
102→        return new PyDictObj<>(map);
103→    }
104→
105→    /**
106→     * Generate all permutations of sets of (key, value) pairs where key is an element of
107→     * keyVals and value is an element of valVals, of size up to and including the input
108→     * size.
109→     *
110→     * @param size    the max size permutation to be generated
111→     * @param keyVals the set of valid keys that can be contained within the dictionary
112→     *                being generated
113→     * @param valVals the set of valid values that can be contained within the dictionary
114→     *                being generated
115→     * @return all permutations of valid (key, value) pairs of length up to and including
116→     * the input size
117→     */
118→    private Set<PyDictObj<KeyType, ValType>> genPermsHelper(int size,
119→                                                            Set<KeyType> keyVals, Set<ValType> valVals) {
120→        // BASE CASE: size 0 -> return a set containing only the empty dictionary
121→        if (size == 0) {
122→            Set<PyDictObj<KeyType, ValType>> perms = new HashSet<>();
123→            perms.add(new PyDictObj<>(new HashMap<>()));
124→            return perms;
125→        }
126→
127→        // RECURSIVE CASE:
128→        // Get all permutations that are of length size - 1
129→        Set<PyDictObj<KeyType, ValType>> oneShorter =
130→                this.genPermsHelper(size - 1, keyVals, valVals);
131→
132→        // Iterate over each shorter dictionary, adding each possible single (key,
133→        // value) pair to it
134→        Set<PyDictObj<KeyType, ValType>> perms = new HashSet<>(oneShorter);
135→        for (PyDictObj<KeyType, ValType> dictObj : oneShorter) {
136→            // Extract the internal HashMap representation
137→            Map<KeyType, ValType> dict = dictObj.getValue();
138→            if (dict.size() < size - 1) {
139→                // For efficiency, let's avoid generating duplicates
140→                continue;
141→            }
142→
143→            // Construct all new dictionaries that result from adding (key, value) to dict
144→            for (KeyType key : keyVals) {
145→                for (ValType val : valVals) {
146→                    // Make sure to clone dict so as not to mutate the original
147→                    Map<KeyType, ValType> dictClone = new HashMap<>(dict);
148→                    dictClone.put(key, val);
149→                    perms.add(new PyDictObj<>(dictClone));
150→                }
151→            }
152→        }
153→        return perms;
154→    }
155→
156→    /**
157→     * Generates all permutations of sets of (key, value) pairs where key is an element of
158→     * keyVals and value is an element of valVals, of size up to and including the max
159→     * value in this.exDomain.
160→     *
161→     * @param keyVals the set of valid keys that can be contained within the dictionary
162→     *                being generated
163→     * @param valVals the set of valid values that can be contained within the dictionary
164→     *                being generated
165→     * @return all permutations of valid (key, value) pairs of length up to and including
166→     * the max value in this.exDomain
167→     */
168→    private Set<PyDictObj<KeyType, ValType>> genDictPerms(Set<KeyType> keyVals,
169→                                                          Set<ValType> valVals) {
170→        // Create all dicts up to (and including) the maximum size
171→        int maxLength = this.exDomainMax();
172→        Set<PyDictObj<KeyType, ValType>> allPerms =
173→                this.genPermsHelper(maxLength, keyVals, valVals);
174→
175→        // Remove dicts of sizes that are not found in this.domain
176→        Set<PyDictObj<KeyType, ValType>> finalPerms = new HashSet<>();
177→        for (PyDictObj<KeyType, ValType> dict : allPerms) {
178→            if (this.exDomain.contains((dict.getValue()).size())) {
179→                finalPerms.add(dict);
180→            }
181→        }
182→        return finalPerms;
183→    }
184→}

