 1→package main.rice.node;
 2→
 3→import main.rice.obj.PyFloatObj;
 4→
 5→import java.util.HashSet;
 6→import java.util.Set;
 7→
 8→/**
 9→ * A representation of a leaf node for generating PyFloatObjs.
10→ */
11→public class PyFloatNode extends APyNode<PyFloatObj> {
12→
13→    /**
14→     * Generates all valid PyFloatObjs within the exhaustive domain.
15→     *
16→     * @return a set of PyFloatObjs comprising the exhaustive domain
17→     */
18→    @Override
19→    public Set<PyFloatObj> genExVals() {
20→        Set<PyFloatObj> vals = new HashSet<>();
21→        for (Number value : this.exDomain) {
22→            vals.add(new PyFloatObj(value.doubleValue()));
23→        }
24→        return vals;
25→    }
26→
27→    /**
28→     * Generates a single valid PyFloatObj within the random domain.
29→     *
30→     * @return a single PyFloatObj selected from the random domain
31→     */
32→    @Override
33→    public PyFloatObj genRandVal() {
34→        return new PyFloatObj(this.ranDomainChoice().doubleValue());
35→    }
36→}

 1→package main.rice.node;
 2→
 3→import main.rice.obj.APyObj;
 4→import main.rice.obj.PySetObj;
 5→import java.util.*;
 6→
 7→/**
 8→ * A representation of a node for generating PySetObjs.
 9→ *
10→ * @param <InnerType> the type of object stored within the sets generated by this node
11→ */
12→public class PySetNode<InnerType extends APyObj> extends AIterablePyNode<
13→        PySetObj<InnerType>, InnerType> {
14→
15→    /**
16→     * Constructor fot a PySetNode; stores a reference to its child node (used to
17→     * generate its contained elements).
18→     *
19→     * @param child a node representing the valid elements for this set
20→     */
21→    public PySetNode(APyNode<InnerType> child) {
22→        this.leftChild = child;
23→    }
24→
25→    /**
26→     * Generates a single valid PySetObj within the random domain; begins by randomly
27→     * generating a valid length (as constrained by the random domain), and then randomly
28→     * generates valid elements. Overridden to disallow duplicates.
29→     *
30→     * @return a single PySetObj selected from the random domain
31→     */
32→    @Override
33→    public PySetObj<InnerType> genRandVal() {
34→        // Randomly select the size, n
35→        int length = this.ranDomainChoice().intValue();
36→
37→        // Randomly select n elements; make sure to continuously monitor the size, as we
38→        // could generate the same element twice resulting in the size not increasing
39→        // from one iteration to the next
40→        Set<InnerType> set = new HashSet<>();
41→        while (set.size() < length) {
42→            InnerType childVal = this.leftChild.genRandVal();
43→            set.add(childVal);
44→        }
45→
46→        return new PySetObj<>(set);
47→    }
48→
49→    /**
50→     * Helper function for generating a PyListObj.
51→     *
52→     * @param innerVals the elements to be contained by the generated PyListObj
53→     * @return a PyListObj object encapsulating the innerVals
54→     */
55→    @Override
56→    protected PySetObj<InnerType> genObj(List<InnerType> innerVals) {
57→        return new PySetObj<>(new HashSet<>(innerVals));
58→    }
59→}

