  1→package main.rice.node;
  2→
  3→import main.rice.obj.APyObj;
  4→import java.util.*;
  5→
  6→/**
  7→ * An abstract class whose instances represent templates for creating Python objects. Each
  8→ * APyNode is a generator for a type of APyObj. For instance, a PyIntNode generates
  9→ * PyIntObjs. If this node represents a compound type, e.g. a list, it will hold
 10→ * references to its child node(s).
 11→ *
 12→ * @param <ObjType> the type of Python object generated by this tree
 13→ */
 14→public abstract class APyNode<ObjType extends APyObj> {
 15→
 16→    /**
 17→     * The domain for exhaustive generation.
 18→     */
 19→    protected List<? extends Number> exDomain;
 20→
 21→    /**
 22→     * The domain for random generation.
 23→     */
 24→    protected List<? extends Number> ranDomain;
 25→
 26→    /**
 27→     * The RNG used for random generation.
 28→     */
 29→    protected Random rand = new Random();
 30→
 31→    /**
 32→     * Returns the left child node.
 33→     *
 34→     * @return the left child node
 35→     */
 36→    public APyNode<?> getLeftChild() {
 37→        return null;
 38→    }
 39→
 40→    /**
 41→     * Returns the right child node.
 42→     *
 43→     * @return the right child node
 44→     */
 45→    public APyNode<?> getRightChild() {
 46→        return null;
 47→    }
 48→
 49→    /**
 50→     * Sets the exhaustive domain to the input list of numbers.
 51→     *
 52→     * @param domain the exhaustive domain
 53→     */
 54→    public void setExDomain(List<? extends Number> domain) {
 55→        this.exDomain = domain;
 56→    }
 57→
 58→    /**
 59→     * Returns the exhaustive domain.
 60→     *
 61→     * @return the exhaustive domain
 62→     */
 63→    public List<? extends Number> getExDomain() {
 64→        return this.exDomain;
 65→    }
 66→
 67→    /**
 68→     * Sets the random domain to the input list of numbers.
 69→     *
 70→     * @param domain the random domain
 71→     */
 72→    public void setRanDomain(List<? extends Number> domain) {
 73→        this.ranDomain = domain;
 74→    }
 75→
 76→    /**
 77→     * Returns the random domain.
 78→     *
 79→     * @return the random domain
 80→     */
 81→    public List<? extends Number> getRanDomain() {
 82→        return this.ranDomain;
 83→    }
 84→
 85→    /**
 86→     * Generates all valid PyObjs of type ObjType within the exhaustive domain.
 87→     *
 88→     * @return a set of PyObjs of type ObjType comprising the exhaustive domain
 89→     */
 90→    public abstract Set<ObjType> genExVals();
 91→
 92→    /**
 93→     * Generates a single valid PyObj of type ObjType within the random domain.
 94→     *
 95→     * @return a single PyObj of type ObjType selected from the random domain
 96→     */
 97→    public abstract ObjType genRandVal();
 98→
 99→    /**
100→     * Makes a random choice from the random domain.
101→     *
102→     * @return a random element from the random domain
103→     */
104→    protected Number ranDomainChoice() {
105→        int choice = this.rand.nextInt(this.ranDomain.size());
106→        return this.ranDomain.get(choice);
107→    }
108→
109→    /**
110→     * Finds and returns the maximum value in the exhaustive domain.
111→     *
112→     * @return the maximum value in the exhaustive domain
113→     */
114→    protected int exDomainMax() {
115→        var maxLength = 0;
116→        for (Number length : this.exDomain) {
117→            if (length.intValue() > maxLength) {
118→                // Found new max
119→                maxLength = length.intValue();
120→            }
121→        }
122→        return maxLength;
123→    }
124→}

  1→package main.rice.node;
  2→
  3→import main.rice.obj.AIterablePyObj;
  4→import main.rice.obj.APyObj;
  5→import java.util.*;
  6→
  7→/**
  8→ * An abstract class whose instances represent generators for iterable Python objects
  9→ * (list, tuple, set, or string). Includes common functionality for generating
 10→ * permutations, though some of the individual sub-classes need to do their own
 11→ * post-processing.
 12→ *
 13→ * @param <OuterType> the outer type of object generated by this node; if we invoke
 14→ *                    this.genExVals(), it will return a Set<OuterType<InnerType>>
 15→ * @param <InnerType> the type of object generated by the leftChild node, which represents
 16→ *                    the type of elements in this iterable object; if we invoke
 17→ *                    this.leftChild.genExVals(), it will return a Set<InnerType>
 18→ */
 19→public abstract class AIterablePyNode<OuterType extends AIterablePyObj<InnerType>,
 20→        InnerType extends APyObj> extends APyNode<OuterType> {
 21→
 22→    /**
 23→     * Overrides the leftChild in the superclass (APyNode) with a more specific type: a
 24→     * generator of InnerType objects.
 25→     */
 26→    protected APyNode<InnerType> leftChild;
 27→
 28→    /**
 29→     * Returns the left child node.
 30→     *
 31→     * @return the left child node
 32→     */
 33→    @Override
 34→    public APyNode<InnerType> getLeftChild() {
 35→        return this.leftChild;
 36→    }
 37→
 38→    /**
 39→     * Generates all valid OuterType objects within the exhaustive domain; begins by
 40→     * generating all valid elements, and then finds all permutations of them of valid
 41→     * length (as constrained by the exhaustive domain).
 42→     *
 43→     * @return a set of OuterTypes comprising the exhaustive domain
 44→     */
 45→    @Override
 46→    public Set<OuterType> genExVals() {
 47→        Set<InnerType> innerVals = this.leftChild.genExVals();
 48→        return this.genPerms(this.exDomainMax(), innerVals);
 49→    }
 50→
 51→    /**
 52→     * Generates a single valid OuterType object within the random domain; begins by
 53→     * randomly generating a valid length (as constrained by the random domain), and then
 54→     * randomly generates valid elements.
 55→     *
 56→     * @return a single OuterType object selected from the random domain
 57→     */
 58→    @Override
 59→    public OuterType genRandVal() {
 60→        // Randomly select the size, n
 61→        int length = this.ranDomainChoice().intValue();
 62→
 63→        // Randomly select n inner values
 64→        List<InnerType> list = new ArrayList<>();
 65→        for (int idx = 0; idx < length; idx++) {
 66→            InnerType childVal = this.genRandInnerVal();
 67→            list.add(childVal);
 68→        }
 69→        return this.genObj(list);
 70→    }
 71→
 72→    /**
 73→     * Helper function for generating one random InnerType object.
 74→     *
 75→     * @return a randomly-generated object of type InnerType
 76→     */
 77→    protected InnerType genRandInnerVal() {
 78→        return this.leftChild.genRandVal();
 79→    }
 80→
 81→    /**
 82→     * Helper function for generating an object of the correct OuterType; will be
 83→     * overridden in the subclasses, where the OuterType is known.
 84→     *
 85→     * @param innerVals the elements to be contained by the generated object
 86→     * @return an OuterType object encapsulating the innerVals
 87→     */
 88→    protected abstract OuterType genObj(List<InnerType> innerVals);
 89→
 90→    /**
 91→     * Helper function that generates all permutations of multiple sizes.
 92→     *
 93→     * @param currSize  the max size permutation to be generated
 94→     * @param innerVals the set of values that can be contained within the iterable being
 95→     *                  randomly-generated
 96→     * @return all permutations of innerVals, according to the input specifications
 97→     */
 98→    protected Set<OuterType> genPerms(int currSize, Set<InnerType> innerVals) {
 99→        // BASE CASE: size 0 -> return a set containing only the empty list
100→        if (currSize == 0) {
101→            Set<OuterType> perms = new HashSet<>();
102→            perms.add(this.genObj(new ArrayList<>()));
103→            return perms;
104→        }
105→
106→        // RECURSIVE CASE:
107→        // Get all permutations that are of length size - 1
108→        Set<OuterType> oneShorter = this.genPerms(currSize - 1, innerVals);
109→        Set<OuterType> perms = new HashSet<>();
110→
111→        // Iterate over each shorter "list" (could actually be a PyListObj, PySetObj, PyTupleObj,
112→        // or PyStringObj)
113→        for (OuterType listObj : oneShorter) {
114→
115→            // Only keep around the smaller version if we wanted that size too
116→            int listSize = listObj.getValue().size();
117→            if (this.exDomain.contains(listSize)) {
118→                perms.add(listObj);
119→            }
120→
121→            // For efficiency, let's avoid generating duplicates by only adding to the largest
122→            // elements of shorterPerms
123→            if (listSize < currSize - 1) {
124→                continue;
125→            }
126→
127→            // Construct all new lists that result from adding val (a possible inner val) to listObj
128→            for (InnerType val : innerVals) {
129→                // Make sure to copt the internal value so as not to mutate the original
130→                List<InnerType> copy = new ArrayList<>(listObj.getValue());
131→                copy.add(val);
132→                OuterType obj = this.genObj(copy);
133→
134→                // Only keep this around if it's the correct size (necessary for PySetObj)
135→                if (obj.getValue().size() == currSize) {
136→                    perms.add(obj);
137→                }
138→            }
139→        }
140→        return perms;
141→    }
142→}

