10→ * @param <InnerType> the type of object stored within the sets generated by this node
11→ */
12→public class PySetNode<InnerType extends APyObj> extends AIterablePyNode<
13→        PySetObj<InnerType>, InnerType> {
14→
15→    /**
16→     * Constructor fot a PySetNode; stores a reference to its child node (used to
17→     * generate its contained elements).
18→     *
19→     * @param child a node representing the valid elements for this set
20→     */
21→    public PySetNode(APyNode<InnerType> child) {
22→        this.leftChild = child;
23→    }
24→
25→    /**
26→     * Generates a single valid PySetObj within the random domain; begins by randomly
27→     * generating a valid length (as constrained by the random domain), and then randomly
28→     * generates valid elements. Overridden to disallow duplicates.
29→     *
30→     * @return a single PySetObj selected from the random domain
31→     */
32→    @Override
33→    public PySetObj<InnerType> genRandVal() {
34→        // Randomly select the size, n
35→        int length = this.ranDomainChoice().intValue();
36→
37→        // Randomly select n elements; make sure to continuously monitor the size, as we
38→        // could generate the same element twice resulting in the size not increasing
39→        // from one iteration to the next
40→        Set<InnerType> set = new HashSet<>();
41→        while (set.size() < length) {
42→            InnerType childVal = this.leftChild.genRandVal();
43→            set.add(childVal);
44→        }
45→
46→        return new PySetObj<>(set);
47→    }
