  1→package main.rice.basegen;
  2→
  3→import main.rice.node.APyNode;
  4→import main.rice.obj.APyObj;
  5→import main.rice.test.TestCase;
  6→import java.util.*;
  7→
  8→/**
  9→ * A class that is used to generate a "base" set of test cases, comprised of the union
 10→ * of a "semi-exhaustive" test set generated within a smaller domain, plus some number of
 11→ * random probes from a larger domain.
 12→ */
 13→public class BaseSetGenerator {
 14→
 15→    /**
 16→     * The nodes that will be used to perform generation.
 17→     */
 18→    private final List<APyNode<?>> nodes;
 19→
 20→    /**
 21→     * The number of random cases to generate.
 22→     */
 23→    private final int numRand;
 24→
 25→    /**
 26→     * The base test set, stored as a field to be accessible to genRandTests().
 27→     */
 28→    private Set<TestCase> baseSet;
 29→
 30→    /**
 31→     * Constructor for a BaseSetGenerator, which initializes the fields.
 32→     *
 33→     * @param nodes   the nodes that will be used to perform generation
 34→     * @param numRand the number of random cases to generate
 35→     */
 36→    public BaseSetGenerator(List<APyNode<?>> nodes, int numRand) {
 37→        this.nodes = nodes;
 38→        this.numRand = numRand;
 39→        this.baseSet = new HashSet<>();
 40→    }
 41→
 42→    /**
 43→     * Generates a the base test set (the union of the semi-exhaustive and random test
 44→     * sets) according to the type and domain specifications in the input list of nodes.
 45→     * Each output test case encapsulates a list of arguments (APyObjs), where the i-th
 46→     * argument is typified by the i-th element in nodes.
 47→     *
 48→     * @return the base test set (as a List, so that we can use indices in the Tester)
 49→     */
 50→    public List<TestCase> genBaseSet() {
 51→        this.baseSet = this.genExTests();
 52→        this.genRandTests();
 53→
 54→        // Convert to a list so that we can use indices in testing
 55→        return new ArrayList<>(this.baseSet);
 56→    }
 57→
 58→    /**
 59→     * Exbaustively generates a set of all valid test cases within the exhaustive
 60→     * domains stored within the nodes.
 61→     *
 62→     * @return a set of valid test cases according to the given specifications
 63→     */
 64→    public Set<TestCase> genExTests() {
 65→        // For each parameter, generate the set of all possible arguments
 66→        List<Set<? extends APyObj>> possibleArgs = new ArrayList<>();
 67→        for (APyNode<?> node : this.nodes) {
 68→            Set<? extends APyObj> args = node.genExVals();
 69→            possibleArgs.add(args);
 70→        }
 71→
 72→        // Generate all possible combinations of arguments (selecting one valid argument
 73→        // for each parameter)
 74→        List<List<APyObj>> combos = generateArgCombos(possibleArgs, 0);
 75→        Set<TestCase> tests = new HashSet<>();
 76→
 77→        // Encapsulate the results within TestCase objects and return
 78→        for (List<APyObj> combo : combos) {
 79→            tests.add(new TestCase(combo));
 80→        }
 81→        return tests;
 82→    }
 83→
 84→    /**
 85→     * Randomly generates a list of valid test cases of size numTests, according to the
 86→     * random domains stored within the nodes. Each output test case encapsulates a list
 87→     * of arguments (APyObjs), where the i-th argument is typified by the i-th element in
 88→     * nodes.
 89→     *
 90→     * @return a list of valid test cases, according to the given specifications
 91→     */
 92→    public Set<TestCase> genRandTests() {
 93→        // Get the goal size for the base test set
 94→        int goalSize = this.baseSet.size() + this.numRand;
 95→        Set<TestCase> randSet = new HashSet<>();
 96→
 97→        // Randomly generate one test at a time until we've generated enough. Need to
 98→        // continually check the size in case we randomly generate the same test twice
 99→        while (this.baseSet.size() < goalSize) {
100→
101→            // Randomly generate each argument
102→            List<APyObj> args = new ArrayList<>();
103→            for (APyNode<?> node : this.nodes) {
104→                APyObj arg = node.genRandVal();
105→                args.add(arg);
106→            }
107→
108→            // Wrap arguments in a TestCase object and add to the base set, making sure
109→            // that it isn't a duplicate of an object in the exhaustive set
110→            TestCase test = new TestCase(args);
111→            if (this.baseSet.add(test)) {
112→                randSet.add(test);
113→            }
114→        }
115→
116→        // Note: randSet is not necessary for any reason other than to allow for better
117→        // isolation during testing. (I originally declared this as a private void helper,
118→        // but changed it so that I can give you partial credit if you get random working
119→        // but not exhaustive.)
120→        return randSet;
121→    }
122→
123→    /**
124→     * Helper function for generateTest; a recursive algorithm for generating all possible
125→     * combinations of arguments across multiple parameters. Uses an additional input,
126→     * index, to keep track of which arguments have already been combined.
127→     *
128→     * @param possibleArgs a list of sets, where the i-th set contains all possible
129→     *                     arguments (as PyObjs) for the i-th parameter
130→     * @param index        the next index within possibleArgs for which we need to
131→     *                     generate all possible combinations
132→     * @return all possible combinations of args, where the i-th element in each sublist
133→     * within the returned list is an element of the i-th set in possibleArgs
134→     */
135→    private static List<List<APyObj>> generateArgCombos(
136→            List<Set<? extends APyObj>> possibleArgs, int index) {
137→
138→        // BASE CASE: index is greater than the last index in possibleArgs ->
139→        // no args remain -> return one empty combination
140→        if (index == possibleArgs.size()) {
141→            List<List<APyObj>> combos = new ArrayList<>();
142→            combos.add(new ArrayList<APyObj>());
143→            return combos;
144→        }
145→
146→        // RECURSIVE CASE: index is within the bounds of possibleArgs ->
147→        // Get all combinations of the later args
148→        List<List<APyObj>> laterCombos = generateArgCombos(possibleArgs, index + 1);
149→
150→        // Get all possible args for the current index
151→        Set<? extends APyObj> currArgs = possibleArgs.get(index);
152→
153→        // For every existing combination, add every possible arg in currArs
154→        List<List<APyObj>> allCombos = new ArrayList<>();
155→        for (APyObj arg : currArgs) {
156→            for (List<APyObj> combo : laterCombos) {
157→                // Make sure to clone so as to not mutate the original
158→                List<APyObj> comboClone = new ArrayList<>(combo);
159→                comboClone.add(0, arg);
160→                allCombos.add(comboClone);
161→            }
162→        }
163→        return allCombos;
164→    }
165→}

     1→package main.rice.test;
     2→
     3→import main.rice.obj.APyObj;
     4→import java.io.*;
     5→import java.util.*;
     6→
     7→/**
     8→ * A class for running a test suite. Encapsulates the ability to run the test suite on a
     9→ * reference implementation to generate the expected results, the ability to create a
    10→ * "wrapper" file for comparing actual results to these expected results, and the ability
    11→ * to run the test suite on a set of files and identify which test cases each file fails
    12→ * on.
    13→ */
    14→public class Tester {
    15→
    16→    /**
    17→     * The name of the function under test.
    18→     */
    19→    private final String funcName;
    20→
    21→    /**
    22→     * The absolute path to the file containing the reference solution (known to be
    23→     * correct).
    24→     */
    25→    private final String solutionPath;
    26→
    27→    /**
    28→     * The absolute path to the directory containing the student implementations.
    29→     */
    30→    private final String implDirPath;
    31→
    32→    /**
    33→     * The set of test cases to be executed on the reference solution.
    34→     */
    35→    private final List<TestCase> tests;
    36→
    37→    /**
    38→     * Constructor for a Tester, which initializes all of the fields using the given
    39→     * inputs.
    40→     *
    41→     * @param funcName     the name of the function under test
    42→     * @param solutionPath the absolute path to the file containing the reference
    43→     *                     implementation
    44→     * @param implDirPath  the absolute path to the directory containing the student
    45→     *                     implementations
    46→     * @param tests        the list of test cases to be executed
    47→     */
    48→    public Tester(String funcName, String solutionPath, String implDirPath,
    49→                  List<TestCase> tests) {
    50→        this.funcName = funcName;
    51→        this.implDirPath = implDirPath;
    52→        this.solutionPath = solutionPath;
    53→        this.tests = tests;
    54→    }
    55→
    56→    /**
    57→     * Computes the expected results by running each test case on the solution file.
    58→     * Stores the results in a list (which is returned) and also creates a .py file
    59→     * containing an equivalent list of the results.
    60→     *
    61→     * @return a list where the i-th element is the result (a string) of running the i-th
    62→     * test case on the reference solution
    63→     * @throws IOException if the path to the solution is invalid
    64→     * @throws InterruptedException if the process is interrupted
    65→     */
    66→    public List<String> computeExpectedResults() throws IOException, InterruptedException {
    67→        // Write an appropriate footer to the solution file to make it executable from
    68→        // the command-line, if the footer doesn't exist already
    69→        this.appendToSolution();
    70→
    71→        // Run each test case on the solution file and gather the results in a map
    72→        List<String> results = new ArrayList<>();
    73→        for (int i = 0; i < this.tests.size(); i++) {
    74→            List<String> args = this.getExpTestArgs(i);
    75→            String result = this.runTestHelper(args);
    76→            results.add(result);
    77→        }
    78→
    79→        // Write the expected results to a .py file, so that they can be accessed via
    80→        // the wrapper. These cached results allow us to only run the solution once per
    81→        // test rather than having to run it once per test per buggy implementation.
    82→        this.outputExpectedResults(results);
    83→
    84→        // Return the results
    85→        return results;
    86→    }
    87→
    88→    /**
    89→     * Runs all tests on all files in the directory of buggy implementations, comparing
    90→     * the outputs to the pre-generated expected results and returning the results in the
    91→     * form of a TestResults object.
    92→     *
    93→     * @return the results of testing
    94→     * @throws IOException if the path to the directory of buggy implementations is
    95→     *                     invalid
    96→     * @throws InterruptedException if the process is interrupted
    97→     */
    98→    public TestResults runTests() throws IOException, InterruptedException {
    99→        // Create the wrapper file
   100→        this.createWrapperFile();
   101→
   102→        // Initialize the outputs
   103→        List<Set<Integer>> caseToFiles = new ArrayList<>();
   104→        for (int i = 0; i < this.tests.size(); i++) {
   105→            caseToFiles.add(new HashSet<>());
   106→        }
   107→        Set<Integer> wrongSet = new HashSet<>();
   108→
   109→        // Get the list of all files in the input directory
   110→        var dir = new File(this.implDirPath);
   111→        String[] filenames = dir.list();
   112→        if (filenames == null) {
   113→            throw new IOException("Error: implDir is empty");
   114→        }
   115→        Arrays.sort(filenames);
   116→
   117→        // If implDirPath didn't actually point to a directory, files would be null
   118→        int trueIndex = 0;
   119→
   120→        // Test each individual file using all tests in the base test set
   121→        for (String filename : filenames) {
   122→            if (!filename.endsWith(".py") || filename.equals("wrapper.py")
   123→                    || filename.equals("expected.py")) {
   124→                continue;
   125→            }
   126→
   127→            // Run each test case on this file, keeping track of which ones caught
   128→            // errors
   129→            HashSet<Integer> caughtBy = new HashSet<>();
   130→            for (int testIndex = 0; testIndex < this.tests.size(); testIndex++) {
   131→                List<String> args = this.getTestArgs(testIndex, filename);
   132→                String result = this.runTestHelper(args);
   133→                if (!result.equals("True")) {
   134→                    caseToFiles.get(testIndex).add(trueIndex);
   135→                    caughtBy.add(testIndex);
   136→                }
   137→            }
   138→
   139→            // Add to wrongSet if applicable
   140→            if (caughtBy.size() > 0) {
   141→                wrongSet.add(trueIndex);
   142→            }
   143→            trueIndex++;
   144→        }
   145→
   146→        // Clean up the pycache that was created
   147→        this.deletePyCache();
   148→
   149→        // Return the results
   150→        return new TestResults(this.tests, caseToFiles, wrongSet);
   151→    }
   152→
   153→    /**
   154→     * Builds the list of command-line arguments for executing the solution in order to
   155→     * get the expected results on a single test case.
   156→     *
   157→     * @param testIndex the index of the test case to be run
   158→     * @return the command-line args for running the given test case through the solution
   159→     */
   160→    private List<String> getExpTestArgs(int testIndex) {
   161→        List<String> args = new ArrayList<>();
   162→
   163→        // The solution must be a python3 file
   164→        args.add("python3");
   165→        args.add(this.solutionPath);
   166→
   167→        // Add each argument as a string; the footer will take care of converting these to
   168→        // Python objects before invoking the function under test
   169→        TestCase test = this.tests.get(testIndex);
   170→        for (APyObj arg : test.getArgs()) {
   171→            args.add(arg.toString());
   172→        }
   173→        return args;
   174→    }
