30→    /**
31→     * Constructor for a TestResults object; initializes all fields.
32→     *
33→     * @param allCases    all test cases that were executed
34→     * @param caseToFiles a list where the i-th element is a set of integers representing
35→     *                    the files that were caught by the i-th test case in allCases
36→     * @param wrongSet    the set of all files that failed one or more tests in allCases
37→     */
38→    public TestResults(List<TestCase> allCases, List<Set<Integer>> caseToFiles,
39→                       Set<Integer> wrongSet) {
40→        this.allCases = allCases;
41→        this.caseToFiles = caseToFiles;
42→        this.wrongSet = wrongSet;
43→    }
44→
45→    /**
46→     * Returns the index-th test case in allCases, if index is within the bounds of
47→     * allCases; null otherwise.
48→     *
49→     * @param index the index of the test case to be returned
50→     * @return the index-th test case in allTests, if index is valid; null otherwise
51→     */
52→    public TestCase getTestCase(int index) {
53→        // Make sure the index is in bounds; if it's out of bounds, return null
54→        if (index >= this.allCases.size() || (this.allCases.size() == 0) || (index < 0)) {
